// gen_bosses2 — 3 multi-phase bosses (content + procedural art).
// File-body form: no import/export. All bindings provided by MEGA_HEADER.
// Engine (enemy.js) auto-drives 3 phases at hp 66%/33%: phaseShift() fires a
// radialBurst reading this.attack {projSpeed,projDamage,projColor,projSprite},
// spawns lesser minions, and enrages. ai:'shooter' bosses hold ground, strafe,
// and fire bursts of (attack.burst + phase) shots fanned by attack.spread.

// ===========================================================================
// Shared boss projectile sprites — big glowing "彈幕" orbs / darts, b2_ prefix.
// ===========================================================================

// b2_fx_emberball — a churning molten fireball with a white-hot core.
defineSprite('b2_fx_emberball', 10, 10, (p) => {
  p.ellipse(5, 5, 4.4, 4.4, P.redD);
  p.ellipse(5, 5, 3.4, 3.4, P.ember);
  p.ellipse(5, 4.5, 2.2, 2.2, P.emberL);
  p.ellipse(4.5, 4, 1, 1, P.white);
  // flickering flame licks
  p.px(5, 0, P.emberL); p.px(9, 5, P.ember); p.px(1, 4, P.ember); p.px(7, 8, P.redL);
  p.outline(P.ink);
}, { anchor: [5, 5] });

// b2_fx_voidlance — a sharp arcane dart of condensed void (points up; engine spins by velocity).
defineSprite('b2_fx_voidlance', 8, 12, (p) => {
  for (let y = 0; y < 12; y++) {
    const w = y < 2 ? 0.4 : (y < 8 ? 0.5 + (y - 2) * 0.36 : 2.6 - (y - 8) * 0.55);
    p.hline(4 - w, 3 + w, y, y < 5 ? P.purpleL : P.purpleD);
  }
  p.vline(0, 11, 4, P.manaL);
  p.px(4, 1, P.white); p.px(3, 4, P.white);
  // trailing void mote
  p.px(4, 11, P.void);
  p.outline(P.ink);
}, { anchor: [4, 6] });

// b2_fx_frostspike — a fast pointed ice javelin with a bright spine.
defineSprite('b2_fx_frostspike', 8, 12, (p) => {
  for (let y = 0; y < 12; y++) {
    const w = y < 1 ? 0.3 : (y < 9 ? 0.5 + (y - 1) * 0.3 : 2.9 - (y - 9) * 0.7);
    p.hline(4 - w, 3 + w, y, y < 6 ? P.ice : P.iceD);
  }
  p.vline(0, 11, 4, P.white);
  p.px(4, 1, P.white);
  p.px(2, 6, P.iceD); p.px(6, 7, P.iceD);
  p.outline(P.ink);
}, { anchor: [4, 6] });

