// procedural art — a horned, ember-cracked demon lord wreathed in living flame.
defineAnim('b2_emberlord', 38, 40, 4, (p, f) => {
  const breathe = (f === 2) ? -1 : 0;          // chest swell
  const flick = (f % 2) ? 1 : 0;               // flame flicker phase
  const oy = breathe;
  const hot = (f % 2) ? P.emberL : P.ember;    // crack glow flicker

  // ---- ambient flame aura behind the body (drawn first) ----
  for (let i = 0; i < 6; i++) {
    const ax = 6 + i * 5 + (i % 2 ? flick : -flick);
    p.vline(4 - flick, 9, ax, P.redD);
    p.px(ax, 3 - flick, hot);
  }

  // ---- molten ground pool / shadow ----
  p.ellipse(19, 38 + oy, 13, 3, P.redD);
  p.ellipse(19, 38 + oy, 9, 2, P.ember);

  // ---- cloven legs ----
  p.rect(11, 29 + oy, 6, 9, P.woodD);
  p.rect(21, 29 + oy, 6, 9, P.woodD);
  p.rect(12, 30 + oy, 4, 6, P.wood);
  p.rect(22, 30 + oy, 4, 6, P.wood);
  // glowing hooves
  p.hline(11, 16, 38 + oy, hot); p.hline(21, 26, 38 + oy, hot);

  // ---- broad fiery torso (lava cracks under charred hide) ----
  const top = 14 + oy, bot = 31 + oy;
  for (let y = top; y <= bot; y++) {
    const t = (y - top) / (bot - top);
    const hw = Math.round(7 + t * 5);
    p.hline(19 - hw, 18 + hw, y, P.woodD);
  }
  for (let y = top + 1; y <= bot - 1; y++) {
    const t = (y - top) / (bot - top);
    const hw = Math.round(5 + t * 3.5);
    p.hline(19 - hw, 18 + hw, y, P.wood);
  }
  // glowing cracks across the chest
  p.line(19, 16 + oy, 13, 28 + oy, hot);
  p.line(19, 16 + oy, 25, 28 + oy, hot);
  p.line(12, 22 + oy, 19, 24 + oy, P.emberL);
  p.line(26, 22 + oy, 19, 24 + oy, P.emberL);
  p.px(15, 20 + oy, P.white); p.px(23, 21 + oy, P.white);

  // molten heart-furnace in the chest
  p.ellipse(19, 22 + oy, 4.5, 4.5, P.redD);
  p.ellipse(19, 22 + oy, 3.2, 3.2, P.ember);
  p.ellipse(19, 21 + oy, 1.8, 1.8, P.emberL);
  p.px(19, 21 + oy, P.white);

  // ---- hulking shoulders + arms hurling fire ----
  p.ellipse(9, 16 + oy, 5, 5, P.woodD); p.ellipse(29, 16 + oy, 5, 5, P.woodD);
  p.ellipse(9, 15 + oy, 3, 3, P.wood);  p.ellipse(29, 15 + oy, 3, 3, P.wood);
  // shoulder flames
  p.line(8, 13 + oy, 6, 7 - flick + oy, P.ember); p.line(30, 13 + oy, 32, 7 - flick + oy, P.ember);
  p.px(6, 7 - flick + oy, P.emberL); p.px(32, 7 - flick + oy, P.emberL);
  // arms ending in burning fists
  p.rect(5, 18 + oy, 4, 9, P.woodD); p.rect(29, 18 + oy, 4, 9, P.woodD);
  p.rect(6, 19 + oy, 2, 6, P.wood);  p.rect(30, 19 + oy, 2, 6, P.wood);
  p.ellipse(6, 28 + oy, 3.4, 3.4, P.redD); p.ellipse(31, 28 + oy, 3.4, 3.4, P.redD);
  p.ellipse(6, 28 + oy, 2, 2, P.ember);    p.ellipse(31, 28 + oy, 2, 2, P.ember);
  p.px(6, 27 + oy, P.white); p.px(31, 27 + oy, P.white);

  // ---- horned demon head ----
  p.ellipse(19, 9 + oy, 6, 6, P.woodD);
  p.ellipse(19, 9 + oy, 4.4, 4.4, P.wood);
  p.ellipse(19, 7 + oy, 3, 2, P.woodL);
  // burning eyes + snarling maw
  p.rect(15, 9 + oy, 8, 3, P.ink2);
  p.rect(16, 9 + oy, 2, 2, hot); p.rect(20, 9 + oy, 2, 2, hot);
  p.px(16, 9 + oy, P.white); p.px(21, 9 + oy, P.white);
  p.hline(16, 22, 12 + oy, P.redD);
  p.px(17, 12 + oy, P.emberL); p.px(20, 12 + oy, P.emberL); // fang glow
  // great curved horns
  p.line(14, 6 + oy, 9, 1 + oy, P.bone); p.line(9, 1 + oy, 11, -1 + oy, P.bone);
  p.line(24, 6 + oy, 29, 1 + oy, P.bone); p.line(29, 1 + oy, 27, -1 + oy, P.bone);
  p.px(11, -1 + oy, P.white); p.px(27, -1 + oy, P.white);

  p.outline(P.ink);
}, { anchor: [19, 38], fps: 6 });

