// procedural art — a hovering many-armed shadow caster crowned by a void halo.
defineAnim('b2_voidweaver', 38, 40, 4, (p, f) => {
  const hover = [0, -1, 0, -2][f % 4];          // levitation bob
  const oy = hover;
  const spin = (f % 2) ? 1 : -1;                // halo rune drift
  const glow = (f % 2) ? P.manaL : P.purpleL;   // core flicker

  // ---- void halo ring of runes behind the head ----
  for (let i = 0; i < 8; i++) {
    const a = (i / 8) * Math.PI * 2 + spin * 0.4;
    const hx = Math.round(19 + Math.cos(a) * 9);
    const hy = Math.round(8 + oy + Math.sin(a) * 9);
    p.px(hx, hy, (i % 2) ? P.purple : glow);
  }

  // ---- shadow on ground (it floats, so faint) ----
  p.ellipse(19, 38, 10, 2.5, P.void);

  // ---- tattered void robe (trapezoid that frays into wisps at the hem) ----
  const top = 12 + oy, bot = 34 + oy;
  for (let y = top; y <= bot; y++) {
    const t = (y - top) / (bot - top);
    const hw = Math.round(4 + t * 8);
    p.hline(19 - hw, 18 + hw, y, P.void);
  }
  for (let y = top + 1; y <= bot - 2; y++) {
    const t = (y - top) / (bot - top);
    const hw = Math.round(2.5 + t * 5.5);
    p.hline(19 - hw, 18 + hw, y, P.purpleD);
  }
  // frayed hem wisps
  for (let i = 0; i < 6; i++) {
    const wx = 8 + i * 4;
    const drop = (i + (f % 2)) % 2;
    p.vline(33 + oy, 36 + drop + oy, wx, P.purpleD);
    p.px(wx, 36 + drop + oy, P.purple);
  }
  // robe seam highlights
  p.line(19, 14 + oy, 13, 32 + oy, P.purple);
  p.line(19, 14 + oy, 25, 32 + oy, P.purple);

  // ---- four spectral arms reaching outward (upper pair raised, lower pair low) ----
  const armPose = (f % 2) ? 1 : 0;
  // upper arms
  p.line(15, 18 + oy, 6, 12 - armPose + oy, P.purpleD);
  p.line(23, 18 + oy, 32, 12 - armPose + oy, P.purpleD);
  p.ellipse(6, 12 - armPose + oy, 2.4, 2.4, P.purple);
  p.ellipse(32, 12 - armPose + oy, 2.4, 2.4, P.purple);
  p.px(6, 12 - armPose + oy, glow); p.px(32, 12 - armPose + oy, glow);
  // lower arms
  p.line(15, 24 + oy, 7, 28 + armPose + oy, P.purpleD);
  p.line(23, 24 + oy, 31, 28 + armPose + oy, P.purpleD);
  p.ellipse(7, 28 + armPose + oy, 2.2, 2.2, P.purple);
  p.ellipse(31, 28 + armPose + oy, 2.2, 2.2, P.purple);
  p.px(7, 28 + armPose + oy, P.manaL); p.px(31, 28 + armPose + oy, P.manaL);

  // ---- central void core in the chest ----
  p.ellipse(19, 22 + oy, 5, 5, P.ink2);
  p.ellipse(19, 22 + oy, 3.6, 3.6, P.purpleD);
  p.ellipse(19, 22 + oy, 2.2, 2.2, glow);
  p.ellipse(19, 21.5 + oy, 1, 1, P.white);
  // orbiting motes around the core
  p.px(13, 22 + oy, P.manaL); p.px(25, 22 + oy, P.manaL);
  p.px(19, 17 + oy, P.purpleL); p.px(19, 27 + oy, P.purpleL);

  // ---- hooded eyeless head with a row of glowing eyes ----
  p.ellipse(19, 8 + oy, 5.5, 5.5, P.void);
  p.ellipse(19, 8 + oy, 4, 4, P.purpleD);
  // shadowed face
  p.rect(15, 7 + oy, 8, 4, P.ink2);
  // three burning void-eyes
  p.px(16, 8 + oy, glow); p.px(19, 8 + oy, glow); p.px(22, 8 + oy, glow);
  p.px(16, 9 + oy, P.white); p.px(19, 9 + oy, P.white); p.px(22, 9 + oy, P.white);
  // jagged hood peaks
  p.line(14, 4 + oy, 12, 0 + oy, P.purpleD); p.line(24, 4 + oy, 26, 0 + oy, P.purpleD);
  p.line(19, 3 + oy, 19, -1 + oy, P.purple);
  p.px(12, 0 + oy, glow); p.px(26, 0 + oy, glow); p.px(19, -1 + oy, P.white);

  p.outline(P.ink);
}, { anchor: [19, 38], fps: 6 });

